import re
import os

files = [
    '../src/app/DiversionAudio.tsx',
    '../src/app/MoncksOfDoverStreet.tsx',
    '../src/app/SunilGavaskar.tsx'
]

def add_lazy_and_min_height(match):
    tag = match.group(0)
    
    # Skip if it already has loading="lazy" (just to be safe)
    if 'loading=' not in tag:
        # insert loading="lazy" after <img
        tag = tag.replace('<img', '<img loading="lazy"', 1)
        
    # check for className
    class_match = re.search(r'className="([^"]*)"', tag)
    if class_match:
        classes = class_match.group(1)
        # check if it already has min-h-
        if 'min-h-' not in classes:
            new_classes = classes + ' min-h-[200px] md:min-h-[400px]'
            tag = tag.replace(f'className="{classes}"', f'className="{new_classes}"')
    else:
        # inject className
        tag = tag.replace('/>', ' className="min-h-[200px] md:min-h-[400px]" />')
        
    return tag

for file_path in files:
    with open(file_path, 'r') as f:
        content = f.read()
        
    # Regex to find <img ... />
    # Non-greedy match until />
    new_content = re.sub(r'<img[^>]+/>', add_lazy_and_min_height, content)
    
    with open(file_path, 'w') as f:
        f.write(new_content)

print("Fixed images!")